<?php declare(strict_types=1);require_once dirname(__DIR__).'/includes/cms.php';if($_SERVER['REQUEST_METHOD']!=='POST'||!validarTokenCsrf($_POST['csrf_token']??null)){cmsFlash('error','Solicitud inválida.');header('Location:index.php');exit;}$id=cmsId($_POST['id']??0);$accion=(string)($_POST['accion']??'');$pdo=obtenerConexion();try{if($accion==='toggle')$pdo->prepare('UPDATE productos SET activo=1-activo WHERE id=:id')->execute(['id'=>$id]);elseif($accion==='eliminar'){$ped=$pdo->prepare('SELECT COUNT(*) FROM pedido_detalles WHERE producto_id=:id');$ped->execute(['id'=>$id]);if((int)$ped->fetchColumn()>0)$pdo->prepare('UPDATE productos SET activo=0,disponible=0,eliminado_at=NOW() WHERE id=:id')->execute(['id'=>$id]);else $pdo->prepare('DELETE FROM productos WHERE id=:id')->execute(['id'=>$id]);}elseif($accion==='eliminar_imagen'){$q=$pdo->prepare('SELECT ruta FROM producto_imagenes WHERE id=:id');$q->execute(['id'=>$id]);$ruta=$q->fetchColumn();$pdo->prepare('DELETE FROM producto_imagenes WHERE id=:id')->execute(['id'=>$id]);cmsEliminarImagenSiNoSeUsa($ruta?:null);cmsFlash('exito','Imagen eliminada.');header('Location: editar.php?id='.cmsId($_POST['producto_id']??0));exit;}cmsFlash('exito','Acción completada.');}catch(Throwable$e){error_log($e->getMessage());cmsFlash('error','No fue posible completar la acción.');}header('Location:index.php');exit;
